#!/usr/bin/env python3
"""Add description and cta keys to Pricing.tier.* in ar.json."""
import json, pathlib

fp = pathlib.Path(__file__).resolve().parent.parent / "lumen-lingo-frontend" / "messages" / "ar.json"
