t["free"]["cta"] = "\u0627\u0628\u062f\u0623 \u0645\u062c\u0627\u0646\u0627\u064b"
t["pro"]["description"] = "\u0644\u0644\u0645\u062a\u0639\u0644\u0645\u064a\u0646 \u0627\u0644\u0645\u0644\u062a\u0632\u0645\u064a\u0646 \u0627\u0644\u0630\u064a\u0646 \u064a\u0631\u064a\u062f\u0648\u0646 \u0627\u0644\u0645\u0632\u064a\u062f \u0645\u0646 \u0627\u0644\u0644\u063a\u0627\u062a \u0648\u062a\u062f\u0631\u064a\u0628 \u063a\u064a\u0631 \u0645\u062d\u062f\u0648\u062f \u0648\u062a\u062c\u0627\u0631\u0628 \u0623\u063a\u0646\u0649."
t["pro"]["cta"] = "\u0627\u0644\u062a\u0631\u0642\u064a\u0629 \u0625\u0644\u0649 Pro"
t["elite"]["description"] = "\u0627\u0641\u062a\u062d \u062a\u062c\u0631\u0628\u0629 LumenLingo \u0627\u0644\u0643\u0627\u0645\u0644\u0629 \u0645\u0639 \u062c\u0645\u064a\u0639 \u0627\u0644\u0644\u063a\u0627\u062a \u0648\u0627\u0644\u0623\u0648\u0636\u0627\u0639 \u0627\u0644\u0645\u062a\u0642\u062f\u0645\u0629 \u0648\u0627\u0644\u0645\u0631\u0626\u064a\u0627\u062a \u0627\u0644\u0645\u0630\u0647\u0644\u0629."
t["elite"]["cta"] = "\u0627\u062e\u062a\u0631 Elite"
t["royal"]["description"] = "\u0627\u0644\u0645\u0633\u062a\u0648\u0649 \u0627\u0644\u0623\u0639\u0644\u0649 \u0644\u0623\u0633\u0627\u062a\u0630\u0629 \u0627\u0644\u0644\u063a\u0627\u062a. \u062c\u0645\u064a\u0639 \u0627\u0644\u0645\u064a\u0632\u0627\u062a\u060c \u0628\u062f\u0648\u0646 \u062d\u062f\u0648\u062f\u060c \u0645\u0632\u0627\u064a\u0627 \u062d\u0635\u0631\u064a\u0629."
t["royal"]["cta"] = "\u0627\u062e\u062a\u0631 Royal"

fp.write_text(json.dumps(data, ensure_ascii=False, indent=2) + "\n", "utf-8")
print("ar.json tier descriptions and CTAs added")
